import React from 'react';
import { motion } from 'framer-motion';
import { ArrowRightIcon } from '@heroicons/react/20/solid';

const stats = [
  { value: '3-6', unit: 'Months', label: 'Avg. Time to LOI' },
  { value: '400+', unit: '', label: 'Deals Sourced' },
  { value: '$500M+', unit: '', label: 'Pipeline Generated' },
];

export default function Hero() {
  return (
    <section className="relative overflow-hidden pt-32 pb-20 lg:pt-40 lg:pb-32">
      {/* Background gradient effects */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute -top-40 -right-40 w-[600px] h-[600px] rounded-full bg-blue-500/10 blur-3xl" />
        <div className="absolute -bottom-40 -left-40 w-[400px] h-[400px] rounded-full bg-blue-600/5 blur-3xl" />
      </div>

      <div className="relative mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="text-center max-w-4xl mx-auto">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
          >
            <div className="inline-flex items-center gap-2 rounded-full bg-blue-500/10 border border-blue-500/20 px-4 py-1.5 mb-8">
              <div className="h-2 w-2 rounded-full bg-blue-400 animate-pulse" />
              <span className="text-sm font-medium text-blue-400">Deal origination for acquisition entrepreneurs</span>
            </div>
          </motion.div>

          <motion.h1
            className="text-4xl sm:text-5xl lg:text-7xl font-extrabold tracking-tight"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.1 }}
          >
            Find Your Business{' '}
            <span className="text-gradient">Faster.</span>
          </motion.h1>

          <motion.p
            className="mt-6 text-lg sm:text-xl text-gray-400 max-w-2xl mx-auto leading-relaxed"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.2 }}
          >
            The average searcher spends 12-24 months looking for a deal.{' '}
            <span className="text-white font-medium">Our clients get under LOI in 3-6.</span>
          </motion.p>

          <motion.div
            className="mt-10 flex flex-col sm:flex-row items-center justify-center gap-4"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.3 }}
          >
            <a
              href="#cta"
              className="group inline-flex items-center gap-2 rounded-full bg-blue-500 px-8 py-4 text-base font-semibold text-white hover:bg-blue-400 transition-all shadow-lg shadow-blue-500/25 hover:shadow-blue-400/30"
            >
              Book a Free Strategy Session
              <ArrowRightIcon className="h-5 w-5 group-hover:translate-x-1 transition-transform" />
            </a>
            <a
              href="#how-it-works"
              className="inline-flex items-center gap-2 rounded-full border border-white/10 px-8 py-4 text-base font-medium text-gray-300 hover:bg-white/5 hover:text-white transition-all"
            >
              See How It Works
            </a>
          </motion.div>
        </div>

        {/* Stats bar */}
        <motion.div
          className="mt-20 grid grid-cols-3 gap-4 max-w-3xl mx-auto"
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.5 }}
        >
          {stats.map((stat) => (
            <div key={stat.label} className="text-center px-4 py-6 rounded-2xl bg-white/[0.03] border border-white/[0.06]">
              <div className="text-2xl sm:text-3xl lg:text-4xl font-bold text-blue-400">
                {stat.value}{stat.unit}
              </div>
              <div className="mt-1 text-xs sm:text-sm text-gray-500">{stat.label}</div>
            </div>
          ))}
        </motion.div>
      </div>
    </section>
  );
}
